import { BreadcrumbProps } from "antd";
import {useContext, useEffect, useMemo} from "react";
import { SpotterRouteObject } from "src";
import {matchRoutes, useLocation} from "react-router-dom";
import {BreadcrumbItemType} from "antd/lib/breadcrumb/Breadcrumb";

export type SptLinkType = 'default' | 'new' | 'replace';
export type ResourceType = 'MENU' | 'FUNCTION'

export interface MenuType {
    id: number;
    code: string;
    type: number;
    description: string;
    parentId: number;
    data: string;
    nextCode: string;
    children: MenuType[]
    spotterMenuNavigationDomainVO: Exclude<SpotterMenuNavigationDomain, 'children'>
}
export interface SpotterMenuNavigationItem {
    // 菜单项的唯一键
    key: string;
    // 导航名称
    name: string;
    // 领域导航默认展示的 icon
    icon: string;
    // 菜单项跳转的 url
    url: string;
    // 菜单的跳转类型
    navigationType?: SptLinkType;
    type: ResourceType,
    children: SpotterMenuNavigationItem[];
}

export interface SpotterMenuNavigationDomain {
    // 菜单项的唯一键
    key: string;
    // 领域导航名称
    name: string;
    // 领域导航默认展示的 icon
    icon: string;
    /**
     * 菜单展示的位置
     * default - 默认，左侧菜单
     * header - 顶部，头部靠右的下拉菜单
     */
    position?: string;
    /**
     * 领域导航的路径前缀，当 location.path.startsWith(activePrefixPath) 为 true 时的任意路径都会让领域导航处于激活状态，
     * 为空时表示该领域导航永远不会处于 active 状态，该情况一般和 type = 'new' 同时使用，表示外链。
     */
    activePrefixPath?: string;
    /**
     * 点击菜单时，如果 indexKey 存在，会使用这 indexKey 指向的子菜单数据进行导航
     * 优先级低于 url 和 type，如果 url 或 type 存在，会覆盖 indexKey 指向的子菜单数据中相同的字段
     */
    indexKey?: string | number;
    /**
     * 菜单项跳转的 path
     * 一般情况下只有没有子菜单时才会用这个字段，如果子菜单中的一项是可以作为默认路由，请使用 indexKey 来指定
     */
    url?: string;
    // 菜单的跳转类型
    navigationType?: SptLinkType;
    // 资源类型
    type: ResourceType,
    // 领域导航激活状态展示的 icon，默认为 `${icon}-fill`，即默认状态 icon 加上填充风格后缀
    activeIcon?: string;
    // 领域导航下的子功能模块导航
    children: SpotterMenuNavigationItem[];
}

const findMenu = (menus: SpotterMenuNavigationDomain[], url: string): any => {
    for (const menusItem of menus) {
        if (menusItem?.url === url) {
            return menusItem;
        }
        if (menusItem?.children?.length > 0) {
            const childRoute = findMenu(menusItem.children, url);
            if (childRoute) {
                return childRoute;
            }
        }
    }
    return null;
};
function findTreeByIdAndParentId(menu: any[], id: number | null, parentId: number | null): any {
    for (const element of menu) {
        if (element.id === id && element.parentId === parentId) {
            return { ...element };
        }
        if (element?.children?.length > 0) {
            const childItem = findTreeByIdAndParentId(element.children, id, element.id);
            if (childItem) {
                return { ...element, children: [childItem] };
            }
        }
    }
    return null;
}

const getLongPathBreadcrumbItems = (longMenu: any, breadcrumbItems: any[]) => {
    if (!longMenu.name) {
        return;
    }
    breadcrumbItems.push({
        // longMenu.url为'-'是为了占位，菜单中占位的二级菜单，需要在配置菜单将其路径设置为'-'
        ...(longMenu.url && longMenu.url !== '-' ? { href: longMenu.url}: {}),
        title: longMenu.name,
    });
    if (longMenu?.children?.length > 0) {
        getLongPathBreadcrumbItems(longMenu?.children?.[0], breadcrumbItems);
    }
};

const getLongPathMenu = (pathSnippets: string[], menus: SpotterMenuNavigationDomain[])=>{
    const init = { url: '', id: null, parentId: null }
    if (menus.length){
        const path = pathSnippets.reduce((prev, _, index) => {
            const url = `/${pathSnippets.slice(0, index + 1).join('/')}`;
            const matchMenu = findMenu(menus, url);
            if (matchMenu?.url?.length > prev?.url?.length) {
                return matchMenu;
            }
            return prev;
        }, init);
        return path;
    }else {
        return  init
    }
}

const transformSubMenuData = (menus?: MenuType[]): SpotterMenuNavigationDomain[] =>
    menus?.length
        ? menus.map(({ data, code, children, parentId, id }) => ({
            ...JSON.parse(data),
            key: code,
            children: transformSubMenuData(children),
            parentId,
            id,
        }))
        : [];


const transformDomainMenuData = (menus: any[]): SpotterMenuNavigationDomain[] =>
    menus?.length
        ? [...menus].map(({ children, data, code, parentId, id }) => ({
            ...(JSON.parse(data) as any),
            key: code,
            children: transformSubMenuData(children),
            parentId,
            id,
        }))
        : [];



export function useBreadcrumbs({
                                   menus,
                                   setBreadcrumbs,
                                   SptPageContainerContext,
                                   routes,
                                   blackList
                               }:{
    menus: any[]
    setBreadcrumbs: (...args: any[])=> any,
    SptPageContainerContext: any
    routes: any[]
    blackList?: string[]
}){

    const location = useLocation()
    const pathSnippets = useMemo(
        () => location.pathname.split('/').filter((p) => p),
        [location.pathname],
    );

    const domainMenus = useMemo(()=>transformDomainMenuData(menus), [menus])
    const { setBreads } = useContext(SptPageContainerContext) as any;

    useEffect(()=>{
        // 黑名单不存在或者路径的第一级没有匹配到黑名单列表中任意一个，则更新面包屑
        if (!blackList || !blackList.includes(pathSnippets[0])){
            const getBreadcrumbItems = (): BreadcrumbProps[] => {
                const longPathMenu = getLongPathMenu(pathSnippets, domainMenus)
                const { url, parentId, id } = longPathMenu || {};
                const longPathBreadcrumbItems: any[] = [];
                if (url) {
                    // 根据最长连续公共path，去菜单数据中找到其树形结构
                    const longMenu = findTreeByIdAndParentId(domainMenus, id, parentId);
                    // 根据找到的树形结构，生成面包屑
                    getLongPathBreadcrumbItems(longMenu, longPathBreadcrumbItems);
                }
                const matchedUrl = url.split('/').filter((i) => i);
                // 匹配菜单路径剩余的面包屑
                const routeBreadcrumbItems = pathSnippets.reduce((p, _, index) => {
                    const customIndex = index + matchedUrl.length;
                    const routeUrl = `/${pathSnippets.slice(0, customIndex + 1).join('/')}`;
                    const matchedRoutes = matchRoutes(routes, { pathname: routeUrl });
                    const route = matchedRoutes?.[matchedRoutes.length - 1].route as SpotterRouteObject;
                    if (route?.name && customIndex < pathSnippets.length) {
                        p.push({
                            ...(route.element ? { href: routeUrl} : {}),
                            title: route.name,
                            // title: route.element ? (
                            //     <Link to={routeUrl} style={{ height: '24px' }}>
                            //         {route.name}
                            //     </Link>
                            // ) : (
                            //     <div className="h-24px">{route.name}</div>
                            // ),
                        });
                    }
                    return p;
                }, [] as BreadcrumbItemType[]);
                return [...longPathBreadcrumbItems, ...routeBreadcrumbItems];
            };
            const breadData = getBreadcrumbItems()
            setBreadcrumbs(breadData)
            setBreads?.(breadData)
        }
    },[pathSnippets, menus])
}
